import{_ as e,c as s,o as t,a5 as n}from"./chunks/framework.C2QCpDA7.js";const u=JSON.parse('{"title":"Commits","description":"","frontmatter":{},"headers":[],"relativePath":"engines/lesli/contributing/commits.md","filePath":"engines/lesli/contributing/commits.md","lastUpdated":1715574060000}'),i={name:"engines/lesli/contributing/commits.md"},a=n(`<h1 id="commits" tabindex="-1">Commits <a class="header-anchor" href="#commits" aria-label="Permalink to &quot;Commits&quot;">​</a></h1><p>The commit is used to confirm a set of changes and make them permanent in the repository, before committing the following points must be fulfilled:</p><ol><li>Download the latest changes from github</li><li>Solve integration errors (merge between commits) if needed</li><li>Run tests</li></ol><p>Each commit has a specific structure in which information regarding work item, project, etc. is included. In addition to including a clear and precise description but also brief of the change that is being confirmed.</p><p>Every commit must meet the <em>Conventional Commits</em> standard</p><h2 id="conventional-commits" tabindex="-1">Conventional Commits <a class="header-anchor" href="#conventional-commits" aria-label="Permalink to &quot;Conventional Commits&quot;">​</a></h2><p>The <a href="https://www.conventionalcommits.org/en/v1.0.0/" target="_blank" rel="noreferrer">Conventional Commits</a> specification is a lightweight convention on top of commit messages. It provides an easy set of rules for creating an explicit commit history; which makes it easier to write automated tools on top of. This convention dovetails with SemVer, by describing the features, fixes, and breaking changes made in commit messages.</p><p>The commit message should be structured as follows:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>[type][optional scope]: [description]</span></span>
<span class="line"><span></span></span>
<span class="line"><span>[optional body]</span></span>
<span class="line"><span></span></span>
<span class="line"><span>[optional footer(s)]</span></span>
<span class="line"><span></span></span>
<span class="line"><span>git commit -m &quot;type: trello/000 Brief description of changes included in this commits&quot;</span></span></code></pre></div><p>An example of such a message:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>fix: ABC-123: Caught Promise exception</span></span>
<span class="line"><span></span></span>
<span class="line"><span>We did not catch the promise exception thrown by the API call</span></span>
<span class="line"><span>and therefore we could not show the error message to the user</span></span></code></pre></div><p>The commit type [type] can take one of these value:</p><ul><li><strong>fix</strong>: A bug fix</li><li><strong>feat</strong>: A new feature</li><li><strong>docs</strong>: Documentation only changes</li><li><strong>perf</strong>: A code change that improves performance</li><li><strong>test</strong>: Adding missing tests or correcting existing tests</li><li><strong>build</strong>: Changes that affect the build system or external dependencies (example scopes: gulp, broccoli, npm)</li><li><strong>style</strong>: Changes that do not affect the meaning of the code (white-space, formatting, missing semi-colons, etc)</li><li><strong>ci</strong>: Changes to our CI configuration files and scripts (example scopes: Travis, Circle, BrowserStack, SauceLabs)</li><li><strong>refactor</strong>: A code change that neither fixes a bug nor adds a feature</li><li><strong>upgrade</strong>: Changes a dependency version number (npm, gem, modules, etc)</li><li><strong>assets</strong>: Changes due a asset compilation process</li><li><strong>release</strong>: New version release process</li><li><strong>BREAKING CHANGE:</strong> a breaking API change</li></ul>`,13),o=[a];function r(l,c,p,m,g,d){return t(),s("div",null,o)}const f=e(i,[["render",r]]);export{u as __pageData,f as default};
